files.content:
:host {
  display: block;
  width: 100%;
  min-width: 0;
  box-sizing: border-box;
  -webkit-user-select: none;
  user-select: none;
}

.code-block {
  width: 100%;
  min-width: 0;
  margin: 0;
  overflow: hidden;
  border-radius: var(--dimension-radius-050);
  background: var(--color-background-strong-neutral);
  color: var(--color-foreground-faint-neutral);
  box-sizing: border-box;
}

.code-block__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--dimension-space-100);
  min-height: var(--dimension-size-400);
  padding: var(--dimension-space-050) var(--dimension-space-100);
  background: var(--color-background-strong-neutral);
  box-sizing: border-box;
}

pre {
  margin: 0;
  padding: var(--dimension-space-150);
  overflow: auto;
  font-family: var(--typography-fontfamily-mono);
  font-size: var(--typography-fontsize-sm);
  line-height: var(--typography-lineheight-sm);
  tab-size: 2;
  -webkit-user-select: text;
  user-select: text;
}

code {
  font: inherit;
  white-space: pre;
}

import { Component, h, Host, Prop, State } from '@stencil/core';

@Component({
  tag: 'ds-code-block',
  styleUrl: 'CodeBlock.css',
  scoped: true,
})
export class CodeBlock {
  @Prop() code: string = '';
  @Prop() language: string = '';
  @Prop() filename: string = '';

  @State() private copied: boolean = false;
  private copiedTimer?: ReturnType<typeof setTimeout>;

  disconnectedCallback() {
    if (this.copiedTimer) clearTimeout(this.copiedTimer);
  }

  private copy = async () => {
    if (!navigator.clipboard || !this.code) return;
    await navigator.clipboard.writeText(this.code);
    this.copied = true;
    if (this.copiedTimer) clearTimeout(this.copiedTimer);
    this.copiedTimer = setTimeout(() => {
      this.copied = false;
    }, 2000);
  };

  render() {
    const label = this.filename || this.language || 'Code';
    return (
      <Host>
        <figure class="code-block">
          <figcaption class="code-block__header">
            <ds-text as="span" variant="text-caption" emphasis color="on-strong">
              {label}
            </ds-text>
            <ds-tooltip label={this.copied ? 'Copied' : 'Copy code'} side="bottom" size="sm">
              <ds-button-unfilled
                variant="icon"
                icon={this.copied ? 'Check' : 'Copy'}
                size="xs"
                aria-label={this.copied ? 'Copied' : 'Copy code'}
                hasBorder={false}
                onDsClick={this.copy}
              />
            </ds-tooltip>
          </figcaption>
          <pre>
            <code>{this.code}</code>
          </pre>
        </figure>
      </Host>
    );
  }
}
